function wrapValue(val: unknown): unknown[] {
  return Array.isArray(val) ? val : [val];
}

export async function seedGradientTokenValues(
  db: any,
  tokenMap: Record<string, any>,
  tenantId: string,
) {
  const platforms = ['web', 'ios', 'android'] as const;
  const rows: any[] = [];

  for (const [name, vals] of Object.entries(VALUES)) {
    // Derive mode and stripped token name from prefix
    const mode = name.startsWith('light.') ? 'light' as const : 'dark' as const;
    const strippedName = name.replace(/^(dark|light)\./, '');
    const token = tokenMap[strippedName];
    if (!token) continue;
    for (const platform of platforms) {
      rows.push({ tokenId: token.id, tenantId, platform, mode, value: wrapValue(vals[platform]), paletteId: null });
    }
  }

  const BATCH_SIZE = 500;
  for (let i = 0; i < rows.length; i += BATCH_SIZE) {
    await db.insert(schema.tokenValues).values(rows.slice(i, i + BATCH_SIZE));
  }

  console.log(`    gradient: ${rows.length} rows`);
  return rows.length;
}